module tb(); logic cpu_overheated; logic arrived; logic gas_tank_empty; logic shut_off_computer_dut; logic keep_driving_dut; logic shut_off_computer_ref; logic keep_driving_ref; reg [10:0] time_of_error; reg [10:0] total_errors; reg error = 0; reg [1:0] queue [0:4]; always @(cpu_overheated or arrived or gas_tank_empty) begin if (error < 5) begin if ( (shut_off_computer_dut !== shut_off_computer_ref) || (keep_driving_dut !== keep_driving_ref) ) begin if (error == 0) time_of_error = $time; error = error + 1; end end end initial begin arrived = 0; gas_tank_empty = 0; cpu_overheated = 0; #1; cpu_overheated = 1; #1; cpu_overheated = 0; arrived = 1; gas_tank_empty = 0; #1; gas_tank_empty = 1; #10; if (error > 0) $display("SIMULATION FAILED - %0d MISMATCHES DETECTED, FIRST AT TIME %0d", error, time_of_error); else $display("SIMULATION PASSED"); $finish; end endmodule